package com.socialblog.follower.repository;import com.socialblog.follower.domain.Follow;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.JpaRepository;import java.util.*;public interface FollowRepository extends JpaRepository<Follow,UUID>{Optional<Follow>findByFollowerIdAndFollowedId(UUID follower,UUID followed);boolean existsByFollowerIdAndFollowedId(UUID follower,UUID followed);Page<Follow>findByFollowerIdOrderByCreatedAtDesc(UUID follower,Pageable p);Page<Follow>findByFollowedIdOrderByCreatedAtDesc(UUID followed,Pageable p);long countByFollowerId(UUID id);long countByFollowedId(UUID id);}
